function ColorSwatch({ color, selected, onClick }: { color: string; selected: boolean; onClick: () => void }) {
  const ref = useRef<HTMLButtonElement>(null);
  useLayoutEffect(() => {
    if (ref.current) ref.current.style.backgroundColor = color;
  }, [color]);
  return (
    <button
      ref={ref}
      type="button"
      aria-label={`Cor ${color}`}
      onClick={onClick}
      className={`h-5 w-5 rounded-full transition-transform ${selected ? "scale-125 ring-2 ring-white ring-offset-1 ring-offset-white dark:ring-offset-[#050816]" : "hover:scale-110"}`}
    />
  );
}

