  useEffect(() => {
    setLoading(true);
    fetch(`/api/automations/regions?assetId=${encodeURIComponent(assetId)}&companySlug=${encodeURIComponent(companySlug)}`)
      .then((r) => r.json())
      .then((data: { regions?: Region[] }) => {
        if (Array.isArray(data.regions)) setRegions(data.regions);
      })
      .catch(() => {})
      .finally(() => setLoading(false));
  }, [assetId, companySlug]);

