  const getRelativePercent = useCallback((e: React.MouseEvent) => {
    const el = containerRef.current;
    if (!el) return { px: 0, py: 0 };
    const rect = el.getBoundingClientRect();
    return {
      px: toPercent(e.clientX - rect.left, rect.width),
      py: toPercent(e.clientY - rect.top, rect.height),
    };
  }, []);

  const handleMouseDown = useCallback((e: React.MouseEvent) => {
    if (e.button !== 0) return;
    e.preventDefault();
    const { px, py } = getRelativePercent(e);
    setDrawing({ startX: px, startY: py, endX: px, endY: py });
    setPending(null);
    setSelectedId(null);
  }, [getRelativePercent]);

  const handleMouseMove = useCallback((e: React.MouseEvent) => {
    if (!drawing) return;
    const { px, py } = getRelativePercent(e);
    setDrawing((d) => d ? { ...d, endX: px, endY: py } : null);
  }, [drawing, getRelativePercent]);

  const handleMouseUp = useCallback(() => {
    if (!drawing) return;
    const rect = rectFromDraw(drawing);
    setDrawing(null);
    // Ignore tiny accidental clicks (< 2% area)
    if (rect.w < 2 || rect.h < 2) return;
    setPending(rect);
    setNewName("");
    setNewNotes("");
  }, [drawing]);

